const http = require('http');
const crypto = require('crypto');

function currentResource() {
  // In a real app this comes from a DB/file. Keep bytes stable per content.
  return JSON.stringify({ id: 42, name: 'Ada Lovelace', role: 'engineer' });
}

function etagFor(body) {
  const hash = crypto.createHash('sha1').update(body).digest('hex').slice(0, 16);
  return '"' + hash + '"';
}

const server = http.createServer((req, res) => {
  if (req.url !== '/api/user' || req.method !== 'GET') {
    res.writeHead(404).end();
    return;
  }

  const body = currentResource();
  const etag = etagFor(body);

  // Common headers on both the 200 and the 304.
  res.setHeader('ETag', etag);
  res.setHeader('Cache-Control', 'no-cache'); // store but always revalidate

  const inm = req.headers['if-none-match'];
  if (inm && inm === etag) {
    res.writeHead(304); // Not Modified: no body
    res.end();
    return;
  }

  res.writeHead(200, {
    'Content-Type': 'application/json',
    'Content-Length': Buffer.byteLength(body)
  });
  res.end(body);
});

server.listen(3000, () => console.log('listening on :3000'));

// Demo:
//   curl -i localhost:3000/api/user            -> 200 + ETag "..."
//   curl -i localhost:3000/api/user \
//        -H 'If-None-Match: "<that-etag>"'      -> 304 Not Modified

// Why it fails:
// 1. PUT + Authorization header => non-simple => browser preflights with OPTIONS.
// 2. Server only sends 'Access-Control-Allow-Origin: *' and nothing else, so:
//    - it does not allow the PUT method (no Allow-Methods)
//    - it does not allow the Authorization header (no Allow-Headers)
//    - with credentials, the wildcard '*' origin is rejected by the browser.
// Result: preflight fails, real PUT is never sent.

// Correct PREFLIGHT response (to the OPTIONS request):
//   HTTP/1.1 204 No Content
//   Access-Control-Allow-Origin: https://app.example.com
//   Access-Control-Allow-Methods: GET, PUT, POST, DELETE
//   Access-Control-Allow-Headers: authorization, content-type
//   Access-Control-Allow-Credentials: true
//   Access-Control-Max-Age: 600
//   Vary: Origin

// Correct ACTUAL response (to the PUT):
//   HTTP/1.1 200 OK
//   Access-Control-Allow-Origin: https://app.example.com
//   Access-Control-Allow-Credentials: true
//   Vary: Origin
//   Content-Type: application/json

// Example Express middleware implementing it safely:
const ALLOWED = new Set(['https://app.example.com']);
function cors(req, res, next) {
  const origin = req.headers.origin;
  if (origin && ALLOWED.has(origin)) {
    res.setHeader('Access-Control-Allow-Origin', origin); // echo, not '*'
    res.setHeader('Access-Control-Allow-Credentials', 'true');
    res.setHeader('Vary', 'Origin');
  }
  if (req.method === 'OPTIONS') {
    res.setHeader('Access-Control-Allow-Methods', 'GET, PUT, POST, DELETE');
    res.setHeader('Access-Control-Allow-Headers', 'authorization, content-type');
    res.setHeader('Access-Control-Max-Age', '600');
    return res.writeHead(204).end();
  }
  next();
}
